def _shade_regions(
    ax: Any,
    t_axis: NDArray[np.float64],
    mask: NDArray[np.bool_],
    color: str,
    alpha: float,
) -> None:
    args = [ax, t_axis, mask, color, alpha]  # type: ignore
    kwargs = {}  # type: ignore
    return _mutmut_trampoline(
        x__shade_regions__mutmut_orig, x__shade_regions__mutmut_mutants, args, kwargs, None
    )


def x__shade_regions__mutmut_orig(
    ax: Any,
    t_axis: NDArray[np.float64],
    mask: NDArray[np.bool_],
    color: str,
    alpha: float,
) -> None:
    """Add vertical shaded regions where mask is True."""
    in_region = False
    start = 0
    for i in range(len(mask)):
        if mask[i] and not in_region:
            start = i
            in_region = True
        elif not mask[i] and in_region:
            ax.axvspan(t_axis[start], t_axis[i - 1], color=color, alpha=alpha)
            in_region = False
    if in_region:
        ax.axvspan(t_axis[start], t_axis[-1], color=color, alpha=alpha)


